  ('medical-tech-moex-12878', 'medical-tech', 'medical-tech-moex-101-716b3930', 'sub-medical-tech-07', NULL, 'single_choice', '金黃色葡萄球菌的毒力因子 protein A，可干擾調理作用（opsonization）及白血球的吞噬作用，是因其具備 何種特性之故？', '["是一種膠原結合蛋白（collagen-binding protein）", "是一種超級抗原，可活化多株T-cells", "可結合IgG1、IgG2及IgG4之Fc部位", "可作為黏素分子（adhesin）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:47+00:00", "source_pdf_sha1": "1b2dc04cf866", "answer_pdf_sha1": "24541fc8fb91", "source_family": "moex-gov-tw", "moex": {"exam_code": "101110", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "101", "exam_name": "101年第2次醫事人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
